const items = $input.all();

if (!items || items.length === 0) {
  console.log('No hay seguimientos pendientes');
  return [];
}

console.log(`${items.length} seguimientos a enviar`);

return items.map(item => {
  const remoteJid = item.json.remote_jid;
  const phoneNumber = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

  return {
    json: {
      id: item.json.id,
      phone_number: phoneNumber,
      remote_jid: remoteJid,
      conversation_id: item.json.chatwoot_conversation_id
    }
  };
});

const prevNode = $('Code - Verificar si hay items').item.json;
const historialResponse = $input.first().json;
const from = prevNode.remote_jid || 'desconocido';
const phoneNumber = prevNode.phone_number || 'desconocido';
const conversationId = prevNode.conversation_id || null;
let mensajes = [];
if (Array.isArray(historialResponse)) { mensajes = historialResponse; }
else if (historialResponse.payload && Array.isArray(historialResponse.payload)) { mensajes = historialResponse.payload; }
else if (historialResponse.data && Array.isArray(historialResponse.data)) { mensajes = historialResponse.data; }
if (mensajes.length === 0) { return [{ json: { contextoManual: 'SIN HISTORIAL PREVIO', sinMensajes: true, from, phoneNumber, conversationId } }]; }
mensajes.sort((a, b) => (a.created_at || 0) - (b.created_at || 0));
const mensajesRecientes = mensajes.slice(-10);
const conversacion = mensajesRecientes.map(msg => { if (msg.message_type === 2) return null; const esCliente = msg.message_type === 0; let contenido = msg.content || ''; if (!contenido) return null; const quien = esCliente ? 'CLIENTE' : 'TU (MAGA)'; const fecha = new Date(msg.created_at * 1000); const timestamp = fecha.toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }); return `[${timestamp}] ${quien}: ${contenido}`; }).filter(Boolean).join('\n');
const contextoManual = `SEGUIMIENTO AUTOMATICO\n\n${conversacion}\n\nInstrucciones: Continua naturalmente, se breve.`;
return [{ json: { contextoManual, totalMensajes: mensajesRecientes.length, from, phoneNumber, conversationId } }];

