const remoteJid = $('SQL - Cancelar Seguimiento2').item.json.remote_jid;
if (remoteJid === null || remoteJid === undefined) { return [{ json: { ...$input.item.json, phone_normalized: '', phone_invalid: true } }]; }
let raw = String(remoteJid).replace('@s.whatsapp.net', '').replace('@c.us', '').trim();
if (raw === '') { return [{ json: { ...$input.item.json, phone_normalized: '', phone_invalid: true } }]; }
const hasPlus = raw.startsWith('+');
const digits = raw.replace(/\D/g, '');
const cleaned = hasPlus ? '+' + digits : digits;
const E164_REGEX = /^\+[1-9]\d{7,14}$/;
let normalized = '';
if (digits.length === 0) { normalized = ''; } else if (hasPlus && E164_REGEX.test(cleaned)) { normalized = cleaned; } else if (digits.startsWith('54')) { normalized = '+' + digits; } else if (digits.startsWith('0')) { normalized = '+549' + digits.slice(1); } else if (digits.startsWith('9') && digits.length >= 11) { normalized = '+54' + digits; } else if (digits.length === 10) { normalized = '+549' + digits; } else { normalized = ''; }
const isValid = normalized !== '' && E164_REGEX.test(normalized);
return [{ json: { ...$input.item.json, phone_normalized: isValid ? normalized : '', phone_invalid: !isValid } }];

